Untuk interaksi dengan Docker API di Python, gunakan library resmi `docker-sdk-python`. Jangan menulis request HTTP manual kecuali untuk kasus spesifik; gunakan SDK untuk stabilitas dan keamanan.

### Prasyarat

Instal dependensi:
```bash
pip install docker
```

### Module: `docker_manager.py`

Module ini membungkus fungsi dasar dengan error handling yang ketat.

```python
import docker
from docker.errors import APIError, NotFound, DockerException
from typing import Optional, List, Dict

class DockerManager:
    def __init__(self, base_url: Optional[str] = None):
        """
        Inisialisasi klien Docker.
        Jika base_url None, akan menggunakan socket UNIX default (/var/run/docker.sock).
        Untuk remote Docker, gunakan tcp://host:port dengan TLS.
        """
        try:
            self.client = docker.DockerClient(base_url=base_url)
            self.api = self.client.api  # Low-level API access jika diperlukan
        except DockerException as e:
            raise RuntimeError(f"Gagal inisialisasi Docker Client: {str(e)}")

    def list_containers(self, all: bool = False) -> List[Dict]:
        """Ambil daftar container."""
        try:
            containers = self.client.containers.list(all=all)
            return [
                {
                    "id": c.id,
                    "name": c.name,
                    "status": c.status,
                    "image": c.image.tags[0] if c.image.tags else c.image.id
                }
                for c in containers
            ]
        except APIError as e:
            raise RuntimeError(f"API Error saat list container: {e.explanation}")

    def get_container(self, container_id: str):
        """Inspeksi container spesifik."""
        try:
            return self.client.containers.get(container_id)
        except NotFound:
            raise ValueError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"API Error: {e.explanation}")

    def run_container(self, image: str, name: str, detach: bool = True, **kwargs) -> str:
        """
        Jalankan container baru.
        kwargs mendukung parameter docker-py standar (ports, volumes, environment, dll).
        """
        try:
            container = self.client.containers.run(image, name=name, detach=detach, **kwargs)
            return container.id
        except APIError as e:
            raise RuntimeError(f"Gagal run container: {e.explanation}")

    def stop_container(self, container_id: str, timeout: int = 10):
        """Stop container dengan timeout."""
        try:
            container = self.get_container(container_id)
            container.stop(timeout=timeout)
        except ValueError as e:
            raise e
        except APIError as e:
            raise RuntimeError(f"Gagal stop container: {e.explanation}")

    def remove_container(self, container_id: str, force: bool = False):
        """Hapus container. Gunakan force=True jika container masih running."""
        try:
            container = self.get_container(container_id)
            container.remove(force=force)
        except ValueError as e:
            raise e
        except APIError as e:
            raise RuntimeError(f"Gagal remove container: {e.explanation}")

    def get_system_info(self) -> Dict:
        """Ambil info sistem Docker."""
        return self.client.info()
```

### Contoh Penggunaan

```python
from docker_manager import DockerManager

if __name__ == "__main__":
    try:
        # Koneksi ke socket lokal
        dm = DockerManager()

        # Cek info
        info = dm.get_system_info()
        print(f"Docker Version: {info['ServerVersion']}")

        # List container aktif
        containers = dm.list_containers()
        for c in containers:
            print(f"[{c['status']}] {c['name']} ({c['id'][:12]})")

